import{_ as t,o,c as a,a3 as d}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Leads Module","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Leads Module | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/leads-overview"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Leads Module | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/leads-overview"}]]},"headers":[],"relativePath":"user-guide/leads-overview.md","filePath":"user-guide/leads-overview.md","lastUpdated":1784586025000}'),i={name:"user-guide/leads-overview.md"};function s(r,e,l,n,c,p){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="leads-module" tabindex="-1">Leads Module <a class="header-anchor" href="#leads-module" aria-label="Permalink to &quot;Leads Module&quot;">​</a></h1><p>Reference business module for the SaleOS platform. Every future module (Tasks, Invoices, Inventory, etc.) must mirror this structure.</p><h2 id="guides" tabindex="-1">Guides <a class="header-anchor" href="#guides" aria-label="Permalink to &quot;Guides&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Audience</th><th>Document</th></tr></thead><tbody><tr><td>Operators / workspace users</td><td><a href="/user-guide/leads">leads-user.md</a></td></tr><tr><td>Engineers</td><td><a href="/developer-guide/leads">leads-developer.md</a></td></tr><tr><td>Production / ops</td><td><a href="/deployment/leads">leads-production.md</a></td></tr><tr><td>Module Development Standard</td><td><a href="/developer-guide/module-development">module-development.md</a></td></tr><tr><td>Tenant API</td><td><a href="/api/tenant-v1-leads">../api/tenant-v1-leads.md</a></td></tr></tbody></table><h2 id="capabilities-sprint-2-crm-ux" tabindex="-1">Capabilities (Sprint 2 CRM UX) <a class="header-anchor" href="#capabilities-sprint-2-crm-ux" aria-label="Permalink to &quot;Capabilities (Sprint 2 CRM UX)&quot;">​</a></h2><ul><li>Pipeline stages (seeded: New → Contacted → Qualified → Proposal → Negotiation → Won / Lost)</li><li><strong>Independent status</strong> — <code>active</code>, <code>waiting</code>, <code>on_hold</code>, <code>closed</code>, <code>archived</code> (not derived from stage)</li><li><strong>Priority</strong> — <code>low</code>, <code>medium</code>, <code>high</code>, <code>urgent</code></li><li><strong>Lead value</strong> — <code>lead_value</code> (renamed from <code>estimated_value</code>; API still accepts the old key as an alias on write)</li><li>Assignment with <strong>assignment history</strong> table</li><li>Notes, follow-ups (create / update-reschedule / complete), activity timeline</li><li><strong>Kanban board (default)</strong> + table view; drag-and-drop opens the detail drawer; save commits the stage change</li><li>KPIs via <code>GET /leads/stats</code>; board via <code>GET /leads/board</code></li><li>Export CSV / XLSX of the current filtered set (<code>leads.export</code>)</li><li>Import CSV / XLSX via multi-step wizard (<code>leads.import</code>) — column mapping, duplicate modes, preview, queued processing, history + reports</li><li>Convert stub (<code>leads.convert</code>) — sets <code>converted_at</code>, records a converted activity, sets status <code>closed</code>; Contacts/Clients deferred</li><li>Assignee scoping — without <code>leads.assign</code>, users only see their own leads</li><li>Module licensing (<code>module:leads</code>) + Spatie permissions</li><li>Audit + activity logging; assignment / follow-up notifications (mail + database)</li></ul><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p><code>leads.view</code> · <code>create</code> · <code>update</code> · <code>delete</code> · <code>assign</code> · <code>export</code> · <code>import</code> · <code>convert</code></p><h2 id="explicitly-deferred" tabindex="-1">Explicitly deferred <a class="header-anchor" href="#explicitly-deferred" aria-label="Permalink to &quot;Explicitly deferred&quot;">​</a></h2><ul><li>Full conversion to Contacts / Companies</li><li>Import retry execution (UI control present; processing deferred)</li><li>Automations / webhooks</li><li>Real-time board sync (Reverb / Echo)</li></ul>',10)])])}const h=t(i,[["render",s]]);export{m as __pageData,h as default};
